import { test, expect } from '@playwright/test';

test('Amazon SG - Add product to cart and validate cart page', async ({ page }) => {
  // 1. Launch browser → Amazon SG.
  await page.goto('https://www.amazon.sg/');
  await expect(page).toHaveTitle(/Amazon\.sg/);

  // 2. Add product to cart.
  // Search for a product (e.g., "laptop")
  const searchBox = page.locator('input#twotabsearchtextbox');
  await searchBox.waitFor({ state: 'visible', timeout: 10000 });
  await searchBox.fill('laptop');
  await page.getByRole('button', { name: 'Go' }).click();

  // Wait for search results to load
  const firstProduct = page.locator('div.s-main-slot div[data-component-type="s-search-result"]').first();
  await firstProduct.waitFor({ state: 'visible', timeout: 15000 });

  // Click on the first product link
  const productLink = firstProduct.locator('h2 a');
  await productLink.click();

  // Wait for product page to load
  await page.waitForLoadState('domcontentloaded');
  // Wait for Add to Cart button to be visible
  const addToCartBtn = page.getByRole('button', { name: /Add to Cart/i });
  await addToCartBtn.waitFor({ state: 'visible', timeout: 15000 });

  // Click Add to Cart
  await addToCartBtn.click();

  // Handle possible side sheet or warranty popup
  // Wait for cart confirmation or close any modal if present
  try {
    // Sometimes Amazon shows a side sheet with "No Thanks" or "Continue to Cart"
    const noThanksBtn = page.getByRole('button', { name: /No Thanks/i });
    if (await noThanksBtn.isVisible({ timeout: 3000 })) {
      await noThanksBtn.click();
    }
  } catch (e) {
    // Ignore if not present
  }

  // Wait for "Added to Cart" confirmation
  await expect(page.getByText('Added to Cart', { exact: false })).toBeVisible({ timeout: 10000 });

  // 3. Click cart icon (id="nav-cart").
  await page.locator('#nav-cart').click();

  // 4. Validate cart page loads.
  await page.waitForURL(/.*\/gp\/cart\/view\.html.*/);
  await expect(page).toHaveURL(/.*\/gp\/cart\/view\.html.*/);
  await expect(page.getByText('Shopping Cart', { exact: false })).toBeVisible({ timeout: 10000 });

  // 5. Close browser.
  // (Playwright test runner handles browser close automatically)
});
